import React, { createContext, useContext, useState } from 'react';

const NFTContext = createContext();

export const useNFT = () => {
  const context = useContext(NFTContext);
  if (!context) {
    throw new Error('useNFT must be used within an NFTProvider');
  }
  return context;
};

export const NFTProvider = ({ children }) => {
  // Mock marketplace listings
  const [marketplaceListings, setMarketplaceListings] = useState([
    {
      id: '1',
      roomId: '4',
      roomName: 'Elite Traders Club',
      nftName: 'Elite Traders Access Pass',
      description: 'Exclusive access to professional trading discussions and alpha calls',
      price: '0.1',
      currency: 'ETH',
      seller: '0x123456789abcdef123456789abcdef123456789a',
      image: 'https://via.placeholder.com/300/6366f1/ffffff?text=Elite+Pass',
      totalSupply: 100,
      sold: 23,
      createdAt: new Date(Date.now() - 86400000)
    },
    {
      id: '2',
      roomId: '5',
      roomName: 'Art Collectors Lounge',
      nftName: 'Art Collector Badge',
      description: 'Connect with fellow art enthusiasts and discover new artists',
      price: '0.05',
      currency: 'ETH',
      seller: '0x987654321fedcba987654321fedcba987654321f',
      image: 'https://via.placeholder.com/300/ec4899/ffffff?text=Art+Badge',
      totalSupply: 50,
      sold: 12,
      createdAt: new Date(Date.now() - 172800000)
    }
  ]);

  // Mock room NFTs created by users
  const [roomNFTs, setRoomNFTs] = useState([
    {
      id: '1',
      roomId: '4',
      name: 'Elite Traders Access Pass',
      symbol: 'ETAP',
      contractAddress: '0xmock123...',
      totalSupply: 100,
      mintPrice: '0.1',
      currency: 'ETH',
      image: 'https://via.placeholder.com/300/6366f1/ffffff?text=Elite+Pass',
      description: 'Exclusive access to professional trading discussions',
      createdBy: '0x742d35Cc6634C0532925a3b8D0C9C0E3C5d5c8E9',
      createdAt: new Date(Date.now() - 86400000)
    }
  ]);

  // Mock user's owned room access NFTs
  const [ownedRoomNFTs, setOwnedRoomNFTs] = useState([
    {
      id: '1',
      roomId: '4',
      tokenId: '001',
      nftName: 'Elite Traders Access Pass',
      roomName: 'Elite Traders Club',
      purchasePrice: '0.1',
      purchaseDate: new Date(Date.now() - 3600000),
      transactionHash: '0xmockpurchase123...'
    }
  ]);

  const mintRoomNFT = async (roomData) => {
    // Mock NFT minting process
    console.log('Minting room access NFT...', roomData);
    await new Promise(resolve => setTimeout(resolve, 3000));

    const newNFT = {
      id: Date.now().toString(),
      roomId: roomData.roomId,
      name: roomData.nftName,
      symbol: roomData.symbol,
      contractAddress: `0xmock${Date.now()}...`,
      totalSupply: roomData.totalSupply,
      mintPrice: roomData.mintPrice,
      currency: roomData.currency,
      image: roomData.image,
      description: roomData.description,
      createdBy: roomData.createdBy,
      createdAt: new Date()
    };

    setRoomNFTs(prev => [...prev, newNFT]);

    return {
      success: true,
      contractAddress: newNFT.contractAddress,
      transactionHash: `0xmint${Date.now()}`,
      nftId: newNFT.id
    };
  };

  const listNFTForSale = async (nftData) => {
    // Mock listing process
    console.log('Listing NFT for sale...', nftData);
    await new Promise(resolve => setTimeout(resolve, 2000));

    const newListing = {
      id: Date.now().toString(),
      roomId: nftData.roomId,
      roomName: nftData.roomName,
      nftName: nftData.nftName,
      description: nftData.description,
      price: nftData.price,
      currency: nftData.currency,
      seller: nftData.seller,
      image: nftData.image,
      totalSupply: nftData.totalSupply,
      sold: 0,
      createdAt: new Date()
    };

    setMarketplaceListings(prev => [...prev, newListing]);

    return {
      success: true,
      listingId: newListing.id,
      transactionHash: `0xlist${Date.now()}`
    };
  };

  const purchaseNFT = async (listingId, buyerAddress) => {
    // Mock purchase process
    console.log(`Purchasing NFT listing ${listingId}...`);
    await new Promise(resolve => setTimeout(resolve, 2500));

    const listing = marketplaceListings.find(l => l.id === listingId);
    if (!listing) throw new Error('Listing not found');

    // Update listing sold count
    setMarketplaceListings(prev => prev.map(l => 
      l.id === listingId 
        ? { ...l, sold: l.sold + 1 }
        : l
    ));

    // Add to user's owned NFTs
    const newOwnedNFT = {
      id: Date.now().toString(),
      roomId: listing.roomId,
      tokenId: (listing.sold + 1).toString().padStart(3, '0'),
      nftName: listing.nftName,
      roomName: listing.roomName,
      purchasePrice: listing.price,
      purchaseDate: new Date(),
      transactionHash: `0xpurchase${Date.now()}`
    };

    setOwnedRoomNFTs(prev => [...prev, newOwnedNFT]);

    return {
      success: true,
      tokenId: newOwnedNFT.tokenId,
      transactionHash: newOwnedNFT.transactionHash
    };
  };

  const checkRoomAccess = (roomId, userAddress) => {
    // Check if user owns the required NFT for the room
    return ownedRoomNFTs.some(nft => nft.roomId === roomId);
  };

  const removeNFTListing = async (listingId) => {
    // Mock removal process
    console.log(`Removing NFT listing ${listingId}...`);
    await new Promise(resolve => setTimeout(resolve, 1000));

    // Remove the listing from marketplace
    setMarketplaceListings(prev => prev.filter(listing => listing.id !== listingId));

    return {
      success: true,
      message: 'NFT listing removed successfully'
    };
  };

  const value = {
    marketplaceListings,
    roomNFTs,
    ownedRoomNFTs,
    mintRoomNFT,
    listNFTForSale,
    purchaseNFT,
    checkRoomAccess,
    removeNFTListing
  };

  return (
    <NFTContext.Provider value={value}>
      {children}
    </NFTContext.Provider>
  );
};

export default NFTProvider;
